<div class="settings-section">
    <h3>Profile Settings</h3>
    <p class="text-muted">Manage your personal information and how others see you.</p>
    <hr />

    @if (Profile is null)
    {
        <p>Loading profile...</p>
        return;
    }

    <div class="profile-layout">
        <div class="avatar-area">
            <div class="avatar-preview">
                @if (!string.IsNullOrWhiteSpace(AvatarUrl))
                {
                    <img src="@AvatarUrl" alt="Avatar" class="avatar-img" />
                }
                else
                {
                    <div class="avatar-placeholder">👤</div>
                }
            </div>
            <div class="avatar-url-display">
                <label class="form-label">Avatar URL</label>
                <input type="url" class="form-control form-control-sm" value="@AvatarUrl"
                       @oninput="e => AvatarUrl = e.Value?.ToString() ?? string.Empty" />
            </div>
        </div>

        <div class="profile-fields">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>

            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>

            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="Bio"></textarea>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>

    @if (_successMessage is not null)
    {
        <div class="alert alert-success mt-3 fade-in" role="alert">
            ✅ @_successMessage
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public UserProfile? Profile { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private bool _saving;
    private string? _successMessage;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_saving)
        {
            LoadFromProfile(Profile);
        }
    }

    private void LoadFromProfile(UserProfile profile)
    {
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        AvatarUrl = profile.AvatarUrl;
        Bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _successMessage = "Profile saved successfully!";
        _ = ClearMessageAfterDelay();
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
        _successMessage = null;
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}
"}

