                       @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
            </div>
        </div>

        <div class="toggle-row">
            <div>
                <strong>Weekly Digest</strong>
                <div class="text-muted small">Get a weekly summary of activity</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       checked="@_weeklyDigest"
                       @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
            </div>
        </div>
    </div>

    <h5 class="mt-4">Muted Channels</h5>
    <p class="text-muted small">Uncheck a channel to mute it.</p>

    <div class="channel-list">
        @foreach (var channel in _allChannels)
        {
            var isMuted = _mutedChannels.Contains(channel);
            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@(!isMuted)"
                       @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">
                    # @channel
                </label>
            </div>
        }
    </div>

    <div class="mt-4">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving..." : "Save Preferences")
        </button>
    </div>

    @if (_successMessage is not null)
    {
        <div class="alert alert-success mt-3 fade-in" role="alert">
            ✅ @_successMessage
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public NotificationPrefs? Prefs { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private bool _saving;
    private string? _successMessage;

    private static readonly string[] _allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_saving)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = new HashSet<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool enabled)
    {
        if (enabled)
            _mutedChannels.Remove(channel);
        else
            _mutedChannels.Add(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _successMessage = "Preferences saved successfully!";
        _ = ClearMessageAfterDelay();
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}
"}

