                Last password change: @Security.LastPasswordChange.Value.ToString("MMM dd, yyyy")
            </p>
        }
    </div>

    <hr />

    <ActiveSessionsTable Sessions="@Security.Sessions"
                         CurrentSessionId="@_currentSessionId"
                         OnRevokeRequested="RequestRevoke" />

    <RevokeSessionDialog Session="@_sessionToRevoke"
                         OnConfirm="ConfirmRevokeAsync"
                         OnCancel="CancelRevoke" />
</div>

@code {
    [Parameter, EditorRequired]
    public SecuritySettings? Security { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnRevokeSession { get; set; }

    private ActiveSession? _sessionToRevoke;

    // Treat the first session as the current one
    private string? _currentSessionId => Security?.Sessions.FirstOrDefault()?.Id;

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}
"}

{"path": "/tmp/sv-f5da3f4385a14e938f88b9795c4eb97b/Components/Pages/Settings/AppearanceSection.razor", "file_text": "@using sv_f5da3f4385a14e938f88b9795c4eb97b.Services

<div class="settings-section">
    <h3>Appearance</h3>
    <p class="text-muted">Customize how the application looks and feels.</p>
    <hr />

    @if (Appearance is null)
    {
        <p>Loading appearance settings...</p>
        return;
    }

    <div class="appearance-layout">
        <div class="appearance-controls">
            <div class="mb-4">
                <h5>Theme</h5>
                <div class="d-flex gap-3">
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="mb-4">
                <h5>Font Size</h5>
                <div class="d-flex gap-3">
                    @foreach (var size in _fontSizes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="mb-4">
                <h5>Language</h5>
                <select class="form-select" style="max-width: 250px;" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="mb-4">
                <h5>Compact Mode</h5>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_compactMode"
                           @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                    <label class="form-check-label">
                        @(_compactMode ? "On — reduced spacing" : "Off — normal spacing")
                    </label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving..." : "Save")
            </button>

            @if (_successMessage is not null)
            {
                <div class="alert alert-success mt-3 fade-in" role="alert">
                    ✅ @_successMessage
                </div>
            }
        </div>

        <div class="preview-area">
            <h5>Preview</h5>
            <div class="preview-box @GetPreviewClasses()">
                <h6 style="margin-bottom: 0.5rem;">Dashboard</h6>
                <p>Welcome back! Here is a quick summary of your recent activity.</p>
                <div class="preview-card">
                    <strong>Tasks</strong>
                    <span>12 remaining</span>
                </div>
                <div class="preview-card">
                    <strong>Messages</strong>
                    <span>3 unread</span>
                </div>
                <button class="btn btn-sm btn-primary mt-2">View All</button>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public AppearanceSettings? Appearance { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private string? _successMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override void OnParametersSet()
    {
        if (Appearance is not null && !_saving)
        {
            _theme = Appearance.Theme;
            _fontSize = Appearance.FontSize;
            _language = Appearance.Language;
            _compactMode = Appearance.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_theme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        });
        classes.Add(_fontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-small",
            "large" => "preview-font-large",
            _ => "preview-font-medium"
        });
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _successMessage = "Appearance saved successfully!";
        _ = ClearMessageAfterDelay();
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}
"}

