toolArgs.file_text:
.settings-section {
    padding: 0.5rem 0;
}

.profile-layout {
    display: grid;
    grid-template-columns: 200px 1fr;
    gap: 2rem;
    align-items: start;
}

.avatar-area {
    text-align: center;
}

.avatar-preview {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    margin: 0 auto 1rem;
    border: 3px solid #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    background-color: #f8f9fa;
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 3rem;
}

.avatar-url-display {
    font-size: 0.85rem;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-5px); }
    to { opacity: 1; transform: translateY(0); }
}

@media (max-width: 640px) {
    .profile-layout {
        grid-template-columns: 1fr;
    }
}

