@using sv_f5da3f4385a14e938f88b9795c4eb97b.Services

@if (Session is not null)
{
    <div class="modal-backdrop" @onclick="Cancel">
        <div class="modal-dialog-box" @onclick:stopPropagation="true">
            <h5>Revoke Session</h5>
            <p>
                Are you sure you want to revoke the session on
                <strong>@Session.Device</strong> from <strong>@Session.Location</strong>?
            </p>
            <p class="text-muted small">This will sign that device out immediately.</p>
            <div class="d-flex gap-2 justify-content-end">
                <button class="btn btn-outline-secondary" @onclick="Cancel" disabled="@_revoking">Cancel</button>
                <button class="btn btn-danger" @onclick="ConfirmAsync" disabled="@_revoking">
                    @(_revoking ? "Revoking..." : "Revoke")
                </button>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public ActiveSession? Session { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnConfirm { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnCancel { get; set; }

    private bool _revoking;

    private async Task ConfirmAsync()
    {
        if (Session is null) return;
        _revoking = true;
        await OnConfirm.InvokeAsync(Session.Id);
        _revoking = false;
    }

    private async Task Cancel() => await OnCancel.InvokeAsync();
}

