toolArgs.file_text:
@using sv_f5da3f4385a14e938f88b9795c4eb97b.Services

<h5>Active Sessions</h5>

@if (Sessions is null || Sessions.Count == 0)
{
    <p class="text-muted">No active sessions.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-hover">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    var isCurrent = session.Id == CurrentSessionId;
                    <tr>
                        <td>
                            @session.Device
                            @if (isCurrent)
                            {
                                <span class="badge bg-success ms-1">Current</span>
                            }
                        </td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("MMM dd, yyyy h:mm tt")</td>
                        <td>
                            @if (!isCurrent)
                            {
                                <button class="btn btn-outline-danger btn-sm"
                                        @onclick="() => OnRevokeRequested.InvokeAsync(session)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<ActiveSession>? Sessions { get; set; }

    [Parameter]
    public string? CurrentSessionId { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<ActiveSession> OnRevokeRequested { get; set; }
}

@using sv_f5da3f4385a14e938f88b9795c4eb97b.Services

<div class="settings-section">
    <h3>Security</h3>
    <p class="text-muted">Manage your password, two-factor authentication, and active sessions.</p>
    <hr />

    @if (Security is null)
    {
        <p>Loading security settings...</p>
        return;
    }

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="tfa-section">
        <h5>Two-Factor Authentication</h5>
        <div class="d-flex align-items-center gap-3">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       checked="@Security.TwoFactorEnabled" disabled />
            </div>
            <span class="badge @(Security.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(Security.TwoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        @if (Security.LastPasswordChange.HasValue)
        {
            <p class="text-muted small mt-2">
                Last password change: @Security.LastPasswordChange.Value.ToString("MMM dd, yyyy")
            </p>
        }
    </div>

    <hr />

    <ActiveSessionsTable Sessions="@Security.Sessions"
                         CurrentSessionId="@_currentSessionId"
                         OnRevokeRequested="RequestRevoke" />

    <RevokeSessionDialog Session="@_sessionToRevoke"
                         OnConfirm="ConfirmRevokeAsync"
                         OnCancel="CancelRevoke" />
</div>

@code {
    [Parameter, EditorRequired]
    public SecuritySettings? Security { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnRevokeSession { get; set; }

    private ActiveSession? _sessionToRevoke;

    // Treat the first session as the current one
    private string? _currentSessionId => Security?.Sessions.FirstOrDefault()?.Id;

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync(string sessionId)
    {
        await OnRevokeSession.InvokeAsync(sessionId);
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}

