toolArgs.file_text:
.settings-section {
    padding: 0.5rem 0;
}

.appearance-layout {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 2rem;
    align-items: start;
}

.preview-area h5 {
    margin-bottom: 0.75rem;
}

.preview-box {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.25rem;
    transition: all 0.3s ease;
}

/* Theme variants */
.preview-light {
    background: #fff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-system {
    background: #f0f0f5;
    color: #333;
    border-color: #bbb;
}

/* Font size variants */
.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
    font-size: 1rem;
}

.preview-font-large {
    font-size: 1.15rem;
}

/* Compact mode */
.preview-compact {
    padding: 0.75rem;
    line-height: 1.3;
}

.preview-compact .preview-card {
    padding: 0.35rem 0.5rem;
    margin-bottom: 0.25rem;
}

.preview-card {
    display: flex;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border-radius: 0.25rem;
    background: rgba(128, 128, 128, 0.1);
    margin-bottom: 0.5rem;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-5px); }
    to { opacity: 1; transform: translateY(0); }
}

@media (max-width: 768px) {
    .appearance-layout {
        grid-template-columns: 1fr;
    }
}

